      "blocking": true
    },
    {
      "expectation_id": "提示以合同条款为准",
      "description": "答案应强调最终规则以保险合同为准，并建议用户查阅合同或咨询保险公司，以控制信息风险。",
      "acceptance_criteria": "实际回答中包含“建议查阅您的保险合同条款获取准确信息”或类似引导性表述。",
      "blocking": false
    }
