  },
  "consumer_contract": {
    "expected_answer_profile": "兼具事实数据与条款注意事项的综合性答复，要求覆盖直接问题并提示潜在限制，语气专业且贴心"
  },
  "semantic_equivalence_checks": [
    {
      "target": "轻症可多次赔付",
      "actual_expression": "轻症可以赔付多次",
      "gold_expression": "轻症可以多次赔付",
